using System.Collections;
using System.Collections.Generic;
using UnityEngine;

/// <summary>
/// Combat akisinin tek kapisi.
/// </summary>
public class CombatDirector : MonoBehaviour
{
    [Header("References")]
    [SerializeField] private GameConfig config;
    [SerializeField] private WeakpointSequence weakpointSequence;
    [SerializeField] private SwipeInput swipeInput;
    [SerializeField] private WeakpointDirectionView directionView;
    [SerializeField] private ComboManager comboManager;
    [SerializeField] private RageManager rageManager;
    [SerializeField] private EnemyApproach enemyApproach;
    [SerializeField] private Camera mainCamera;

    [Header("Hit Test")]
    [SerializeField] private float hitRadiusPx = 80f;
    [SerializeField] private float minDeltaPx = 8f;
    [SerializeField] private float rageMinDeltaPx = 2f;

    [Header("Retry")]
    [SerializeField] private float retryDelaySeconds = 1.0f;

    [Header("State (Read-only)")]
    [SerializeField] private bool combatActive = false;
    [SerializeField] private bool executionOpen = false;
    [SerializeField] private bool firstTouchMade = false;
    [SerializeField] private int successCount = 0;
    [SerializeField] private int failCount = 0;

    public event System.Action OnCombatSuccess;
    public event System.Action<string> OnCombatFail;

    public bool IsCombatActive => combatActive;
    public bool IsWaitingForRetry => waitingForRetry;

    private List<WeakpointDirection> activeChain = new List<WeakpointDirection>();
    private bool hitRegisteredThisTarget = false;
    private bool waitingForRetry = false;


    private void Awake()
    {
        if (swipeInput == null)
            swipeInput = FindFirstObjectByType<SwipeInput>();
        if (weakpointSequence == null)
            weakpointSequence = FindFirstObjectByType<WeakpointSequence>();
        if (directionView == null)
            directionView = FindFirstObjectByType<WeakpointDirectionView>();
        if (comboManager == null)
            comboManager = FindFirstObjectByType<ComboManager>();
        if (rageManager == null)
            rageManager = FindFirstObjectByType<RageManager>();
        if (enemyApproach == null)
            enemyApproach = FindFirstObjectByType<EnemyApproach>();
        if (mainCamera == null)
            mainCamera = Camera.main;
        Debug.Log("[CombatDirector] Awake OK.");
    }

    private void OnEnable()
    {
        if (weakpointSequence == null) return;
        weakpointSequence.OnExecutionWindowStart += HandleExecutionWindowStart;
        weakpointSequence.OnChainAdvance += HandleChainAdvance;
        weakpointSequence.OnChainSuccess += HandleChainSuccess;
        weakpointSequence.OnChainFail += HandleChainFail;
    }

    private void OnDisable()
    {
        if (weakpointSequence == null) return;
        weakpointSequence.OnExecutionWindowStart -= HandleExecutionWindowStart;
        weakpointSequence.OnChainAdvance -= HandleChainAdvance;
        weakpointSequence.OnChainSuccess -= HandleChainSuccess;
        weakpointSequence.OnChainFail -= HandleChainFail;
    }

    private void Update()
    {
        if (!combatActive) return;
        if (waitingForRetry) return;
        if (!executionOpen) return;
        if (weakpointSequence == null || swipeInput == null) return;
        if (weakpointSequence.CurrentPhase != WeakpointSequence.Phase.ExecutionWindow) return;

        bool isRage = rageManager != null && rageManager.IsRageActive;

        // --- Finger-lift fail ---
        if (firstTouchMade && !swipeInput.IsDown)
        {
            weakpointSequence.ForceFailExternal("FingerLift");
            return;
        }

        if (!swipeInput.IsDown) return;

        // --- Hareket var mi? ---
        Vector2 delta = swipeInput.RawDeltaPx;
        float requiredDelta = isRage ? rageMinDeltaPx : minDeltaPx;
        if (delta.magnitude < requiredDelta) return;


        // ===== NORMAL HIT =====
        if (directionView == null) return;

        Vector2 markerScreenPos;
        if (!directionView.TryGetActiveMarkerScreenPos(out markerScreenPos)) return;

        Vector2 fp = swipeInput.FingerPosition;
        float dist = Vector2.Distance(fp, markerScreenPos);
        if (dist > hitRadiusPx) return;

        if (hitRegisteredThisTarget) return;
        hitRegisteredThisTarget = true;

        firstTouchMade = true;
        comboManager?.RegisterHit();

        if (!isRage)
            rageManager?.RegisterHit();

        if (isRage)
        {
            FeedbackManager.Instance?.PlayRageHitFeedback();
            AudioManager.Instance?.PlayHitRage();
            Debug.Log($"[CombatDirector] RAGE HIT! dist={dist:F0}px");
        }
        else
        {
            FeedbackManager.Instance?.PlayHitFeedback();
            AudioManager.Instance?.PlayHitNormal();
            Debug.Log($"[CombatDirector] HIT! dist={dist:F0}px");
        }

        weakpointSequence.SubmitHit();
    }

    // --- Event handlers ---

    private void HandleExecutionWindowStart(float duration)
    {
        executionOpen = true;
        firstTouchMade = false;
        hitRegisteredThisTarget = false;
        Debug.Log("[CombatDirector] Execution acildi.");

    }

    private void HandleChainAdvance(int newIndex)
    {
        hitRegisteredThisTarget = false;
        Debug.Log($"[CombatDirector] Chain advance -> {newIndex}");
    }

    private void HandleChainSuccess()
    {
        successCount++;
        combatActive = false;
        executionOpen = false;
        firstTouchMade = false;
        hitRegisteredThisTarget = false;
        comboManager?.RegisterChainSuccess();
        enemyApproach?.SetRageVisual(false);
        FeedbackManager.Instance?.PlayChainSuccessFeedback();
        AudioManager.Instance?.PlayChainSuccess();
        OnCombatSuccess?.Invoke();
        Debug.Log($"[CombatDirector] BASARI! Toplam={successCount}");
    }

    private void HandleChainFail(string reason)
    {
        failCount++;
        executionOpen = false;
        firstTouchMade = false;
        hitRegisteredThisTarget = false;

        comboManager?.RegisterTimeout();
        rageManager?.ResetRage();

        enemyApproach?.SetRageVisual(false);
        FeedbackManager.Instance?.PlayFailFeedback();
        AudioManager.Instance?.PlayFailPunish();
        OnCombatFail?.Invoke(reason);
        Debug.Log($"[CombatDirector] FAIL. Sebep={reason} Toplam={failCount}");

        if (combatActive && activeChain != null && activeChain.Count > 0)
            StartCoroutine(RetryAfterDelay());
        else
            combatActive = false;
    }

    private IEnumerator RetryAfterDelay()
    {
        waitingForRetry = true;
        yield return new WaitForSecondsRealtime(retryDelaySeconds);
        waitingForRetry = false;

        if (!combatActive) yield break;

        Debug.Log("[CombatDirector] Retry: ayni dusmanin zinciri yeniden basliyor.");
        weakpointSequence.StartExecutionDirectly(activeChain);
    }

    // --- Public API ---

    public void StartCombatSequence(List<WeakpointDirection> chain)
    {
        if (weakpointSequence == null)
        {
            Debug.LogError("[CombatDirector] WeakpointSequence yok!");
            return;
        }

        bool isRage = rageManager != null && rageManager.IsRageActive;

        // Rage aktifken chain'i tek elemanlı yap — silüet = tek weakpoint
        if (isRage)
        {
            activeChain = new List<WeakpointDirection> { WeakpointDirection.Up };
            Debug.Log("[CombatDirector] RAGE: Tek rage weakpoint kullanılacak.");
        }
        else
        {
            activeChain = new List<WeakpointDirection>(chain);
        }

        combatActive = true;
        executionOpen = false;
        firstTouchMade = false;
        hitRegisteredThisTarget = false;
        waitingForRetry = false;

        if (isRage)
        {
            Debug.Log("[CombatDirector] SetRageVisual(true) cagriliyor.");
            enemyApproach?.SetRageVisual(true);
            weakpointSequence.StartExecutionDirectly(activeChain);
        }
        else
        {
            weakpointSequence.StartSequence(activeChain);
        }
    }

    public WeakpointSequence GetSequence() => weakpointSequence;

    public void SetCurrentEnemy(EnemyApproach newEnemyApproach)
    {
        enemyApproach = newEnemyApproach;
    }
}

using System.Collections;
using System.Collections.Generic;
using UnityEngine;

/// <summary>
/// SADECE TEST AMACLI. Nihai sistem değildir.
/// Play'e basınca 1 saniye bekler, sonra otomatik bir zincir başlatır.
/// Konsol loglarını izleyerek hit/miss test edebilirsin.
/// </summary>
public class CombatTriggerTest : MonoBehaviour
{
    [Header("References")]
    [SerializeField] private CombatDirector combatDirector;

    [Header("Test Chain")]
    [SerializeField] private List<WeakpointDirection> testChain = new List<WeakpointDirection>
    {
        WeakpointDirection.Right,
        WeakpointDirection.Up,
        WeakpointDirection.Left
    };

    [Header("Settings")]
    [Tooltip("Play'den kaç saniye sonra zincir baslasin.")]
    [SerializeField] private float delaySeconds = 1.5f;

    [Tooltip("Zincir bitince kaç saniye sonra yeniden baslasin. 0 = tekrar baslatma.")]
    [SerializeField] private float repeatAfterSeconds = 3f;

    private void Awake()
    {
        if (combatDirector == null)
            combatDirector = FindFirstObjectByType<CombatDirector>();
    }

    private void Start()
    {
        StartCoroutine(TriggerLoop());
    }

private IEnumerator TriggerLoop()
    {
        while (true)
        {
            yield return new WaitForSecondsRealtime(delaySeconds);

            Debug.Log("CombatTriggerTest: Zincir baslatiliyor...");
            combatDirector.StartCombatSequence(new List<WeakpointDirection>(testChain));

            // Zincir bitene kadar bekle (Done veya Idle olana kadar)
            yield return new WaitUntil(() =>
            {
                var seq = combatDirector.GetSequence();
                if (seq == null) return true;
                var phase = seq.CurrentPhase;
                return !combatDirector.IsCombatActive && !combatDirector.IsWaitingForRetry;
            });

            if (repeatAfterSeconds <= 0f)
                yield break;

            yield return new WaitForSecondsRealtime(repeatAfterSeconds);
        }
    }
}

using UnityEngine;
using TMPro;

/// <summary>
/// Fruit Ninja tarzi combo sistemi.
/// - Basarili her hit combo sayacini arttirir
/// - Sadece timeout combo'yu sifirlar
/// - Finger lift combo'yu bozmaz
/// </summary>
public class ComboManager : MonoBehaviour
{
    [Header("References")]
    [SerializeField] private TextMeshProUGUI comboText;
    [SerializeField] private TextMeshProUGUI hitCountText;

    [Header("State (Read-only)")]
    [SerializeField] private int comboCount = 0;
    [SerializeField] private int totalHits = 0;

    // Events
    public event System.Action<int> OnComboChanged;

    public int ComboCount => comboCount;

    private void Awake()
    {
        UpdateUI();
    }

    /// <summary>Basarili hit - combo artar</summary>
    public void RegisterHit()
    {
        comboCount++;
        totalHits++;
        UpdateUI();
        OnComboChanged?.Invoke(comboCount);
        Debug.Log($"[Combo] Hit! Combo={comboCount} TotalHits={totalHits}");
    }

    /// <summary>Sadece timeout'ta cagrilir - combo sifirlanir</summary>
    public void RegisterTimeout()
    {
        if (comboCount > 0)
            Debug.Log($"[Combo] Timeout! Combo {comboCount} -> 0");
        comboCount = 0;
        UpdateUI();
        OnComboChanged?.Invoke(comboCount);
    }

    /// <summary>Zincir basarili tamamlandi - combo devam eder (sifirlanmaz)</summary>
    public void RegisterChainSuccess()
    {
        // Fruit Ninja gibi: basari combo'yu bozmaz, devam eder
        Debug.Log($"[Combo] Chain success! Combo={comboCount} devam ediyor.");
    }

    private void UpdateUI()
    {
        if (comboText != null)
        {
            if (comboCount <= 0)
                comboText.text = "0";
            else if (comboCount == 1)
                comboText.text = "HIT!";
            else
                comboText.text = $"x{comboCount} COMBO!";
        }

        if (hitCountText != null)
            hitCountText.text = $"Hits: {totalHits}";
    }
}

using UnityEngine;

/// <summary>
/// Düşmanın koridordan yaklaşmasını yönetir.
/// </summary>
public class EnemyApproach : MonoBehaviour
{
    [Header("References")]
    [SerializeField] private CombatDirector combatDirector;
    [SerializeField] private EnemyArchetypeData archetypeData;

    [Header("Approach Settings")]
    [SerializeField] private Vector3 spawnPosition = new Vector3(0f, 0f, 30f);
    [SerializeField] private Vector3 stopPosition = new Vector3(0f, 0f, 6f);
    [SerializeField] private float approachSpeed = 4f;
    [SerializeField] private float telegraphTriggerDistance = 8f;

   

    [Header("Rage Hit")]
    [Tooltip("Silüet hit alanını genişletme çarpanı. 1.0 = tam bounds, 1.3 = %30 padding")]
    [SerializeField] private float rageHitPadding = 1.3f;

    [Header("Timing")]
    [SerializeField] private float deathPauseSeconds = 1.5f;
    [SerializeField] private float respawnDelaySeconds = 1.0f;
    [SerializeField] private float deathFlashDuration = 0.3f;

    [Header("State (Read-only)")]
    [SerializeField] private State currentState = State.Idle;

    public enum State { Idle, Approaching, TelegraphTriggered, WaitingForResult, Dead }

    private Renderer cachedRenderer;

    private void Awake()
    {
        if (combatDirector == null)
            combatDirector = FindFirstObjectByType<CombatDirector>();
        cachedRenderer = GetComponentInChildren<Renderer>();
    }

    private void OnEnable()
    {
        if (combatDirector == null) return;
        combatDirector.OnCombatSuccess += HandleCombatSuccess;
        combatDirector.OnCombatFail += HandleCombatFail;
    }

    private void OnDisable()
    {
        if (combatDirector == null) return;
        combatDirector.OnCombatSuccess -= HandleCombatSuccess;
        combatDirector.OnCombatFail -= HandleCombatFail;
    }

    private void Start()
    {
        StartApproach();
    }

    private void Update()
    {
        if (archetypeData == null)
        {
            Debug.LogError("[EnemyApproach] archetypeData yok!");
            return;
        }

        if (currentState != State.Approaching) return;

        transform.position = Vector3.MoveTowards(
            transform.position,
            stopPosition,
            archetypeData.approachSpeed * Time.deltaTime
        );

        float distToCamera = transform.position.z;
        if (distToCamera <= archetypeData.telegraphTriggerDistance)
            TriggerTelegraph();
    }

    // --- Public: Rage hit testi için ekran sınırları ---

    /// <summary>
    /// Düşmanın Renderer bounds'unun 8 köşesini ekrana projekte ederek
    /// gerçek ekran Rect'ini döndürür.
    /// Rage hit testi için CombatDirector tarafından kullanılır.
    /// </summary>
    public bool TryGetScreenRect(Camera cam, out Rect screenRect)
    {
        screenRect = Rect.zero;
        if (cam == null || cachedRenderer == null) return false;

        Bounds bounds = cachedRenderer.bounds;

        // Bounds'un 8 köşesini hesapla
        Vector3 center = bounds.center;
        Vector3 extents = bounds.extents;

        Vector3[] corners = new Vector3[8];
        corners[0] = center + new Vector3(-extents.x, -extents.y, -extents.z);
        corners[1] = center + new Vector3(-extents.x, -extents.y, extents.z);
        corners[2] = center + new Vector3(-extents.x, extents.y, -extents.z);
        corners[3] = center + new Vector3(-extents.x, extents.y, extents.z);
        corners[4] = center + new Vector3(extents.x, -extents.y, -extents.z);
        corners[5] = center + new Vector3(extents.x, -extents.y, extents.z);
        corners[6] = center + new Vector3(extents.x, extents.y, -extents.z);
        corners[7] = center + new Vector3(extents.x, extents.y, extents.z);

        // Her köşeyi ekran koordinatına çevir
        float minX = float.MaxValue;
        float maxX = float.MinValue;
        float minY = float.MaxValue;
        float maxY = float.MinValue;

        for (int i = 0; i < 8; i++)
        {
            Vector3 sp = cam.WorldToScreenPoint(corners[i]);

            // Kameranın arkasındaysa geçersiz
            if (sp.z < 0f) return false;

            if (sp.x < minX) minX = sp.x;
            if (sp.x > maxX) maxX = sp.x;
            if (sp.y < minY) minY = sp.y;
            if (sp.y > maxY) maxY = sp.y;
        }

        // Padding uygula — hit alanını biraz genişlet
        float w = maxX - minX;
        float h = maxY - minY;
        float padW = w * (rageHitPadding - 1f) * 0.5f;
        float padH = h * (rageHitPadding - 1f) * 0.5f;

        screenRect = new Rect(minX - padW, minY - padH, w + padW * 2f, h + padH * 2f);

        return true;
    }

    // --- Internal ---

    private void StartApproach()
    {
        transform.position = spawnPosition;
        currentState = State.Approaching;
        Debug.Log("[EnemyApproach] Yaklaşma başladı.");
    }

    private void TriggerTelegraph()
    {
        currentState = State.TelegraphTriggered;
        Debug.Log("[EnemyApproach] Telegraph tetiklendi.");

        if (archetypeData == null)
        {
            Debug.LogError("[EnemyApproach] archetypeData yok!");
            return;
        }

        if (archetypeData.pattern == null || archetypeData.pattern.Length == 0)
        {
            Debug.LogError("[EnemyApproach] archetypeData.pattern bos!");
            return;
        }

        combatDirector.StartCombatSequence(
            new System.Collections.Generic.List<WeakpointDirection>(archetypeData.pattern)
        );

        currentState = State.WaitingForResult;
    }

    private void HandleCombatSuccess()
    {
        currentState = State.Dead;
        Debug.Log("[EnemyApproach] Düşman öldü. Sonraki başlıyor...");
        StartCoroutine(DeathFlashThenRespawn());
    }

    private System.Collections.IEnumerator DeathFlashThenRespawn()
    {
        if (cachedRenderer != null)
        {
            Color original = cachedRenderer.material.color;
            cachedRenderer.material.color = Color.red;
            yield return new WaitForSeconds(deathFlashDuration);
            cachedRenderer.material.color = original;
        }
        StartCoroutine(RespawnAfterDelay());
    }

    public void SetRageVisual(bool rageActive)
    {
        Transform outline = transform.Find("OutlineQuad");
        if (outline != null)
            outline.gameObject.SetActive(rageActive);
    }

    private void HandleCombatFail(string reason)
    {
        Debug.Log($"[EnemyApproach] Fail ({reason}), düşman bekliyor.");
        StartCoroutine(PunishFlash());
    }

    private System.Collections.IEnumerator PunishFlash()
    {
        if (cachedRenderer != null)
        {
            Color original = cachedRenderer.material.color;
            cachedRenderer.material.color = Color.white;
            yield return new WaitForSeconds(0.15f);
            cachedRenderer.material.color = original;
        }
    }

    private System.Collections.IEnumerator RespawnAfterDelay()
    {
        yield return new WaitForSecondsRealtime(deathPauseSeconds);
        yield return new WaitForSecondsRealtime(respawnDelaySeconds);
        StartApproach();
    }

    private void OnDrawGizmosSelected()
    {
        Gizmos.color = Color.blue;
        Gizmos.DrawWireSphere(spawnPosition, 0.3f);
        Gizmos.color = Color.green;
        Gizmos.DrawWireSphere(stopPosition, 0.3f);
        Gizmos.color = Color.yellow;
        Gizmos.DrawWireSphere(new Vector3(stopPosition.x, stopPosition.y, telegraphTriggerDistance), 0.3f);
    }
}

