using System.Collections;
using UnityEngine;

public class FeedbackManager : MonoBehaviour
{
    public static FeedbackManager Instance { get; private set; }

    [Header("Hit Stop")]
    [SerializeField] private float hitStopTimeScale = 0.05f;
    [SerializeField] private float hitStopDuration = 0.06f;

    [Header("Screen Shake — Normal Hit")]
    [SerializeField] private float hitShakeMagnitude = 0.05f;
    [SerializeField] private float hitShakeDuration = 0.08f;

    [Header("Screen Shake — Rage Hit")]
    [SerializeField] private float rageShakeMagnitude = 0.09f;
    [SerializeField] private float rageShakeDuration = 0.1f;

    [Header("Screen Shake — Fail")]
    [SerializeField] private float failShakeMagnitude = 0.15f;
    [SerializeField] private float failShakeDuration = 0.2f;

    [Header("Screen Shake — Chain Success")]
    [SerializeField] private float successShakeMagnitude = 0.07f;
    [SerializeField] private float successShakeDuration = 0.12f;

    [Header("References")]
    [SerializeField] private Camera targetCamera;

    private Vector3 cameraOrigin;
    private Coroutine shakeCoroutine;
    private bool isHitStopped = false;

    // SlashTrail bu property'yi okur — shake sırasında trail noktası eklenmez
    public bool IsShaking { get; private set; }

    private void Awake()
    {
        if (Instance != null && Instance != this) { Destroy(gameObject); return; }
        Instance = this;

        if (targetCamera == null)
            targetCamera = Camera.main;

        if (targetCamera != null)
            cameraOrigin = targetCamera.transform.localPosition;
    }

    // ── Public API ──────────────────────────────────────────────

    public void PlayHitFeedback()
    {
        TriggerHitStop(hitStopDuration, hitStopTimeScale);
        TriggerShake(hitShakeMagnitude, hitShakeDuration);
    }

    public void PlayRageHitFeedback()
    {
        TriggerHitStop(hitStopDuration, hitStopTimeScale);
        TriggerShake(rageShakeMagnitude, rageShakeDuration);
    }

    public void PlayFailFeedback()
    {
        TriggerShake(failShakeMagnitude, failShakeDuration);
    }

    public void PlayChainSuccessFeedback()
    {
        TriggerShake(successShakeMagnitude, successShakeDuration);
    }

    // ── Internal ────────────────────────────────────────────────

    private void TriggerHitStop(float duration, float scale)
    {
        if (isHitStopped) return;
        StartCoroutine(HitStopRoutine(duration, scale));
    }

    private void TriggerShake(float magnitude, float duration)
    {
        if (targetCamera == null) return;
        if (shakeCoroutine != null)
            StopCoroutine(shakeCoroutine);
        shakeCoroutine = StartCoroutine(ShakeRoutine(magnitude, duration));
    }

    private IEnumerator HitStopRoutine(float duration, float scale)
    {
        isHitStopped = true;
        Time.timeScale = scale;
        yield return new WaitForSecondsRealtime(duration);
        Time.timeScale = 1f;
        isHitStopped = false;
    }

    private IEnumerator ShakeRoutine(float magnitude, float duration)
    {
        IsShaking = true;  // ← shake başladı, SlashTrail bunu okur

        float elapsed = 0f;
        while (elapsed < duration)
        {
            float t = elapsed / duration;
            float currentMag = Mathf.Lerp(magnitude, 0f, t);
            Vector3 offset = new Vector3(
                Random.Range(-1f, 1f) * currentMag,
                Random.Range(-1f, 1f) * currentMag,
                0f
            );
            targetCamera.transform.localPosition = cameraOrigin + offset;
            elapsed += Time.unscaledDeltaTime;
            yield return null;
        }

        targetCamera.transform.localPosition = cameraOrigin;
        shakeCoroutine = null;
        IsShaking = false;  // ← shake bitti
    }

    private void OnDisable()
    {
        Time.timeScale = 1f;
        IsShaking = false;
        if (targetCamera != null)
            targetCamera.transform.localPosition = cameraOrigin;
    }
}

﻿using UnityEngine;
using TMPro;

/// <summary>
/// Rage sistemi.
/// - Her doğru hit rage doldurur (combo'dan bağımsız)
/// - Rage dolunca aktif olur: weakpoint zorunluluğu kalkar
/// - Fail → rage sıfırlanır
/// </summary>
public class RageManager : MonoBehaviour
{
    [Header("Tuning")]
    [SerializeField] private int hitsToActivate = 6;

    [Header("Debug UI (opsiyonel)")]
    [SerializeField] private TextMeshProUGUI rageText;

    [Header("State (Read-only)")]
    [SerializeField] private int rageHits = 0;
    [SerializeField] private bool rageActive = false;

    public bool IsRageActive => rageActive;

    public void RegisterHit()
    {
        if (rageActive) return;
        rageHits++;
        if (rageHits >= hitsToActivate)
        {
            rageActive = true;
            AudioManager.Instance?.PlayRageActivate();
            Debug.Log("[Rage] RAGE AKTIF!");
        }
        UpdateUI();
    }

    public void ResetRage()
    {
        rageHits = 0;
        rageActive = false;
        Debug.Log("[Rage] Reset.");
        UpdateUI();
    }

    private void UpdateUI()
    {
        if (rageText == null) return;
        if (rageActive)
            rageText.text = "RAGE!";
        else
            rageText.text = $"Rage: {rageHits}/{hitsToActivate}";
    }
}

using System.Collections.Generic;
using UnityEngine;

[RequireComponent(typeof(MeshFilter))]
[RequireComponent(typeof(MeshRenderer))]
public class SlashTrail : MonoBehaviour
{
    [Header("References")]
    [SerializeField] private SwipeInput swipeInput;
    [SerializeField] private Camera targetCamera;
    [SerializeField] private Material trailMaterial;

    [Header("Trail Ayarları")]
    [SerializeField] private float trailDepth = 2f;
    [SerializeField] private float startWidth = 0.18f;
    [SerializeField] private float endWidth = 0.0f;
    [SerializeField] private float pointLifetime = 0.3f;
    [SerializeField] private float minPointDistancePx = 6f;

    [Header("Neon Renk")]
    [SerializeField] private Color colorStart = new Color(1f, 1f, 1f, 1f);
    [SerializeField] private Color colorMid = new Color(0.4f, 0.8f, 1f, 0.9f);
    [SerializeField] private Color colorEnd = new Color(0.1f, 0.5f, 1f, 0f);

    private struct TrailPoint
    {
        public Vector3 localPosition; // kamera local uzayında
        public float birthTime;
    }

    private List<TrailPoint> points = new List<TrailPoint>();
    private MeshFilter meshFilter;
    private MeshRenderer meshRenderer;
    private Mesh mesh;
    private Vector2 lastAddedScreenPos;

    private void Awake()
    {
        if (swipeInput == null)
            swipeInput = FindFirstObjectByType<SwipeInput>();
        if (targetCamera == null)
            targetCamera = Camera.main;

        meshFilter = GetComponent<MeshFilter>();
        meshRenderer = GetComponent<MeshRenderer>();

        mesh = new Mesh();
        mesh.name = "SlashTrailMesh";
        meshFilter.mesh = mesh;

        if (trailMaterial != null)
            meshRenderer.material = trailMaterial;

        meshRenderer.sortingOrder = 10;
    }

    /// Ekran koordinatını kamera local uzayına çevirir
    private Vector3 ScreenToLocal(Vector2 screenPos)
    {
        // Viewport koordinatına çevir (0-1 arası)
        float vx = screenPos.x / Screen.width;
        float vy = screenPos.y / Screen.height;

        // Kameranın görüş alanındaki gerçek boyutu hesapla
        float depth = targetCamera.nearClipPlane + trailDepth;
        float halfH = Mathf.Tan(targetCamera.fieldOfView * 0.5f * Mathf.Deg2Rad) * depth;
        float halfW = halfH * targetCamera.aspect;

        // Local uzayda pozisyon (-1..1 aralığını gerçek boyuta çevir)
        float lx = (vx * 2f - 1f) * halfW;
        float ly = (vy * 2f - 1f) * halfH;
        float lz = depth;

        return new Vector3(lx, ly, lz);
    }

    private void Update()
    {
        if (swipeInput == null || targetCamera == null) return;

        float now = Time.time;
        points.RemoveAll(p => now - p.birthTime > pointLifetime);

        if (swipeInput.IsDown)
        {
            bool shaking = FeedbackManager.Instance != null && FeedbackManager.Instance.IsShaking;

            if (!shaking)
            {
                Vector2 fingerPos = swipeInput.FingerPosition;
                float screenDist = Vector2.Distance(fingerPos, lastAddedScreenPos);
                bool shouldAdd = points.Count == 0 || screenDist >= minPointDistancePx;

                if (shouldAdd)
                {
                    Vector3 localPos = ScreenToLocal(fingerPos);
                    points.Add(new TrailPoint { localPosition = localPos, birthTime = now });
                    lastAddedScreenPos = fingerPos;
                }
            }
        }
        else
        {
            lastAddedScreenPos = Vector2.zero;
        }

        BuildMesh(now);
    }

    private void BuildMesh(float now)
    {
        mesh.Clear();

        int count = points.Count;
        if (count < 2) return;

        var vertices = new Vector3[count * 2];
        var colors = new Color[count * 2];
        var uvs = new Vector2[count * 2];
        var triangles = new int[(count - 1) * 6];

        // Kamera local uzayında Z eksenine dik normal
        Vector3[] normals = new Vector3[count];
        for (int i = 0; i < count; i++)
        {
            Vector3 dir;
            if (i == 0)
                dir = (points[1].localPosition - points[0].localPosition).normalized;
            else if (i == count - 1)
                dir = (points[count - 1].localPosition - points[count - 2].localPosition).normalized;
            else
            {
                Vector3 d1 = (points[i].localPosition - points[i - 1].localPosition).normalized;
                Vector3 d2 = (points[i + 1].localPosition - points[i].localPosition).normalized;
                dir = ((d1 + d2) * 0.5f).normalized;
            }
            // Kamera local uzayında Z eksenine dik → X/Y düzleminde normal
            normals[i] = new Vector3(-dir.y, dir.x, 0f).normalized;
        }

        for (int i = 0; i < count; i++)
        {
            float t = (float)i / (count - 1);
            float age = (now - points[i].birthTime) / pointLifetime;
            float alpha = Mathf.Clamp01(1f - age);
            float headFade = Mathf.Clamp01((float)(count - 1 - i) / Mathf.Max(1, count * 0.15f));
            alpha *= headFade;

            float width = Mathf.Lerp(endWidth, startWidth, 1f - t) * 0.5f;

            vertices[i * 2] = points[i].localPosition + normals[i] * width;
            vertices[i * 2 + 1] = points[i].localPosition - normals[i] * width;

            Color c = t < 0.5f
                ? Color.Lerp(colorStart, colorMid, t * 2f)
                : Color.Lerp(colorMid, colorEnd, (t - 0.5f) * 2f);
            c.a *= alpha;

            colors[i * 2] = c;
            colors[i * 2 + 1] = c;
            uvs[i * 2] = new Vector2(t, 0f);
            uvs[i * 2 + 1] = new Vector2(t, 1f);
        }

        int tri = 0;
        for (int i = 0; i < count - 1; i++)
        {
            int a = i * 2, b = i * 2 + 1, c = i * 2 + 2, d = i * 2 + 3;
            triangles[tri++] = a; triangles[tri++] = c; triangles[tri++] = b;
            triangles[tri++] = b; triangles[tri++] = c; triangles[tri++] = d;
        }

        mesh.vertices = vertices;
        mesh.colors = colors;
        mesh.uv = uvs;
        mesh.triangles = triangles;
        mesh.RecalculateBounds();
    }

    private void OnDestroy()
    {
        if (mesh != null) Destroy(mesh);
    }
}

/// <summary>
/// Weakpoint zincirindeki yön tipleri.
/// Tüm combat ve UI scriptleri bu enum'u kullanir.
/// </summary>
public enum WeakpointDirection
{
    None  = 0,
    Up    = 1,
    Down  = 2,
    Left  = 3,
    Right = 4
}

using System;
using System.Collections.Generic;
using UnityEngine;

/// <summary>
/// Weakpoint zincirinin tum mantigini yonetir.
///
/// Telegraph akisi:
///   1) TelegraphReveal: marker'lar sirayla belirir (1 -> 1+2 -> 1+2+3)
///   2) TelegraphHold:   hepsi birlikte kisa sure durur
///   3) ExecutionWindow: sadece 1. weakpoint kalir, oyuncu swipe yapar
///
/// Retry akisi (telegraph olmadan):
///   - StartExecutionDirectly() ile dogrudan ExecutionWindow'a geçilir
///
/// Fail kaynaklari:
///   - Timeout (UpdateExecutionWindow)
///   - FingerLift (CombatDirector -> ForceFailExternal)
/// </summary>
public class WeakpointSequence : MonoBehaviour
{
    // ─── Events ──────────────────────────────────────────────────────────

    public event Action<int> OnTelegraphStep;
    public event Action<float> OnExecutionWindowStart;
    public event Action OnExecutionWindowEnd;
    public event Action<int> OnChainAdvance;
    public event Action OnChainSuccess;
    public event Action<string> OnChainFail;

    // ─── Inspector ───────────────────────────────────────────────────────

    [Header("Referanslar")]
    [SerializeField] private WeakpointDirectionView directionView;
    [SerializeField] private GameConfig config;

    [Header("Ayarlar")]
    [Tooltip("Her marker'in arasindaki sure (saniye)")]
    [SerializeField] private float telegraphRevealInterval = 1f;
    [Tooltip("Tum marker'lar gorunce bekleme suresi (saniye)")]
    [SerializeField] private float telegraphHoldSeconds = 1f;

    [Header("Chain (Read-only)")]
    [SerializeField] private List<WeakpointDirection> chain = new();
    [SerializeField] private int currentIndex = 0;

    [Header("State (Read-only)")]
    [SerializeField] private Phase currentPhase = Phase.Idle;
    [SerializeField] private float phaseTimer = 0f;
    [SerializeField] private int revealedCount = 0;

    // ─── Enum ────────────────────────────────────────────────────────────

    public enum Phase { Idle, TelegraphReveal, TelegraphHold, ExecutionWindow, Done }

    // ─── Properties ──────────────────────────────────────────────────────

    public Phase CurrentPhase => currentPhase;
    public int CurrentIndex => currentIndex;
    public int ChainLength => chain.Count;

    public WeakpointDirection CurrentTarget =>
        (currentIndex < chain.Count) ? chain[currentIndex] : WeakpointDirection.None;

    // ─── Public API ──────────────────────────────────────────────────────

    /// <summary>
    /// Telegraph dahil tam akisi baslatir. Yeni dusmanlar icin kullanilir.
    /// </summary>
    public void StartSequence(List<WeakpointDirection> directions)
    {
        if (directions == null || directions.Count == 0)
        {
            Debug.LogWarning("WeakpointSequence: Bos zincir baslatılamaz.");
            return;
        }

        chain = new List<WeakpointDirection>(directions);
        currentIndex = 0;
        revealedCount = 0;
        phaseTimer = 0f;
        currentPhase = Phase.TelegraphReveal;

        directionView?.HideAll();

        // Ilk marker'i hemen goster
        RevealNextMarker();

        Debug.Log($"WeakpointSequence: Zincir basladi (telegraph). Adim={chain.Count}");
    }

    /// <summary>
    /// Telegraph olmadan dogrudan ExecutionWindow'a gecer.
    /// Fail sonrasi retry icin kullanilir.
    /// </summary>
    public void StartExecutionDirectly(List<WeakpointDirection> directions)
    {
        if (directions == null || directions.Count == 0)
        {
            Debug.LogWarning("WeakpointSequence: Bos zincir.");
            return;
        }

        chain = new List<WeakpointDirection>(directions);
        currentIndex = 0;
        revealedCount = chain.Count; // telegraph atlandigi icin tamam say
        phaseTimer = 0f;

        directionView?.HideAll();

        OpenExecutionWindow();

        Debug.Log($"WeakpointSequence: Dogrudan execution basladi (retry). Adim={chain.Count}");
    }

    /// <summary>
    /// CombatDirector'dan dogrudan hit bildirimi.
    /// Normal execution icin: tek weakpoint ilerletir.
    /// </summary>
    public void SubmitHit()
    {
        if (currentPhase != Phase.ExecutionWindow) return;

        currentIndex++;
        OnChainAdvance?.Invoke(currentIndex);
        Debug.Log($"WeakpointSequence: HIT! {currentIndex}/{chain.Count}");

        if (currentIndex >= chain.Count)
            CompleteChain();
        else
            ShowExecutionTarget();
    }

    /// <summary>
    /// Rage hit icin: tum chain'i atlayip direkt success uretir.
    /// Tek slash ile aninda execution tamamlanir.
    /// </summary>
    public void ForceCompleteChain()
    {
        if (currentPhase != Phase.ExecutionWindow) return;

        currentIndex = chain.Count;
        Debug.Log("WeakpointSequence: RAGE — ForceCompleteChain!");
        CompleteChain();
    }

    /// <summary>
    /// CombatDirector finger-lift tespiti yaptiginda bu metotu cagirir.
    /// </summary>
    public void ForceFailExternal(string reason)
    {
        if (currentPhase != Phase.ExecutionWindow) return;
        FailChain(reason);
    }

    public void ResetSequence()
    {
        currentPhase = Phase.Idle;
        currentIndex = 0;
        revealedCount = 0;
        chain.Clear();
        phaseTimer = 0f;
        Time.timeScale = 1f;
        directionView?.HideAll();
    }

    // ─── Update ──────────────────────────────────────────────────────────

    private void Update()
    {
        if (config == null) return;

        phaseTimer += Time.unscaledDeltaTime;

        switch (currentPhase)
        {
            case Phase.TelegraphReveal: UpdateTelegraphReveal(); break;
            case Phase.TelegraphHold: UpdateTelegraphHold(); break;
            case Phase.ExecutionWindow: UpdateExecutionWindow(); break;
        }
    }

    private void UpdateTelegraphReveal()
    {
        if (phaseTimer < telegraphRevealInterval) return;
        phaseTimer = 0f;

        if (revealedCount < chain.Count)
            RevealNextMarker();
        else
            EnterTelegraphHold();
    }

    private void UpdateTelegraphHold()
    {
        if (phaseTimer >= telegraphHoldSeconds)
            OpenExecutionWindow();
    }

    private void UpdateExecutionWindow()
    {
        if (phaseTimer >= config.executionWindowSeconds)
            FailChain("Timeout");
    }

    // ─── Internal ────────────────────────────────────────────────────────

    private void RevealNextMarker()
    {
        if (directionView == null || revealedCount >= chain.Count) return;

        directionView.ShowTelegraphStep(revealedCount, chain[revealedCount]);
        OnTelegraphStep?.Invoke(revealedCount);
        AudioManager.Instance?.PlayTelegraphStep();
        Debug.Log($"WeakpointSequence: Telegraph goster index={revealedCount} dir={chain[revealedCount]}");

        revealedCount++;
    }

    private void EnterTelegraphHold()
    {
        currentPhase = Phase.TelegraphHold;
        phaseTimer = 0f;
        Debug.Log("WeakpointSequence: TelegraphHold basladi.");
    }

    private void OpenExecutionWindow()
    {
        currentIndex = 0;
        currentPhase = Phase.ExecutionWindow;
        phaseTimer = 0f;

        Time.timeScale = config.timeScaleDuringExecution;

        ShowExecutionTarget();

        OnExecutionWindowStart?.Invoke(config.executionWindowSeconds);
        Debug.Log($"WeakpointSequence: ExecutionWindow acildi. Sure={config.executionWindowSeconds}s");
    }

    private void ShowExecutionTarget()
    {
        if (directionView == null) return;
        // Sadece siradaki aktif marker gorunur, diğerleri gizli
        directionView.HideAll();
        directionView.ShowTelegraphStep(currentIndex, CurrentTarget);
    }

    private void CompleteChain()
    {
        currentPhase = Phase.Done;
        Time.timeScale = 1f;
        directionView?.HideAll();
        OnExecutionWindowEnd?.Invoke();
        OnChainSuccess?.Invoke();
        Debug.Log("WeakpointSequence: BASARILI!");
    }

    private void FailChain(string reason)
    {
        currentPhase = Phase.Done;
        Time.timeScale = 1f;
        directionView?.HideAll();
        OnExecutionWindowEnd?.Invoke();
        OnChainFail?.Invoke(reason);
        Debug.Log($"WeakpointSequence: BASARISIZ. Sebep={reason}");
    }
}

using UnityEngine;

public class AudioManager : MonoBehaviour
{
    public static AudioManager Instance { get; private set; }

    [Header("SFX Clips")]
    [SerializeField] private AudioClip hitNormal;
    [SerializeField] private AudioClip hitRage;
    [SerializeField] private AudioClip failPunish;
    [SerializeField] private AudioClip rageActivate;
    [SerializeField] private AudioClip chainSuccess;
    [SerializeField] private AudioClip telegraphStep;

    [Header("Volume")]
    [Range(0f, 1f)][SerializeField] private float masterVolume = 1f;

    private AudioSource audioSource;

    private void Awake()
    {
        if (Instance != null && Instance != this) { Destroy(gameObject); return; }
        Instance = this;

        audioSource = gameObject.AddComponent<AudioSource>();
        audioSource.playOnAwake = false;
    }

    private void Play(AudioClip clip, float volumeScale = 1f)
    {
        if (clip == null) return;
        audioSource.PlayOneShot(clip, masterVolume * volumeScale);
    }

    public void PlayHitNormal() => Play(hitNormal);
    public void PlayHitRage() => Play(hitRage, 1.2f);
    public void PlayFailPunish() => Play(failPunish);
    public void PlayRageActivate() => Play(rageActivate);
    public void PlayChainSuccess() => Play(chainSuccess);
    public void PlayTelegraphStep() => Play(telegraphStep);
}

using System.Collections.Generic;
using UnityEngine;

public class CorridorLoop : MonoBehaviour
{
    [Header("References")]
    [SerializeField] private Transform reference;           // Main Camera
    [SerializeField] private List<Transform> segments;      // Corridor_01, Corridor_02, ...

    [Header("Motion")]
    [SerializeField] private float speed = 6f;

    [Header("Recycle")]
    [Tooltip("Segment tamamen kameran�n arkas�na ge�ince recycle olsun.")]
    [SerializeField] private float recycleBehind = 5f;

    private void Reset()
    {
        if (reference == null && Camera.main != null)
            reference = Camera.main.transform;
    }

    private void Start()
    {
        if (reference == null && Camera.main != null)
            reference = Camera.main .transform;

        // Ba�lang��ta segmentleri ger�ek u�lar�na g�re arka arkaya diz
        AlignSegmentsByBounds();
    }

    private void Update()
    {
        if (segments == null || segments.Count == 0) return;

        // 1) Hepsini geriye kayd�r
        float dz = speed * Time.deltaTime;
        for (int i = 0; i < segments.Count; i++)
        {
            if (segments[i] == null) continue;
            segments[i].position += Vector3.back * dz;
        }

        if (reference == null) return;

        // 2) Kamera arkas�na tamamen d��en segmentleri en �ne yap��t�r
        float thresholdZ = reference.position.z - recycleBehind;

        for (int i = 0; i < segments.Count; i++)
        {
            Transform seg = segments[i];
            if (seg == null) continue;

            Bounds b = GetWorldBounds(seg);

            // Segmentin en �n ucu bile threshold'un arkas�na ge�tiyse tamamen arkada demektir
            if (b.max.z < thresholdZ)
            {
                float frontMostMaxZ = FindFrontMostMaxZ();

                // Bu segmentin current bounds.min.z ile pivot aras�ndaki offset'i koruyarak ta��
                float pivotToMin = seg.position.z - b.min.z;

                Vector3 p = seg.position;
                p.z = frontMostMaxZ + pivotToMin;   // minZ => frontMostMaxZ olacak �ekilde
                seg.position = p;
            }
        }
    }

    private void AlignSegmentsByBounds()
    {
        // segments listesindeki s�raya g�re diziyoruz: 0 en arkada, sonra 1,2...
        // �stersen 0'� ba�lang�� segmentin olarak sahnede istedi�in yere koy, di�erleri ona yap��s�n.

        if (segments == null || segments.Count == 0) return;

        // �lk segmenti referans al
        Transform first = segments[0];
        if (first == null) return;

        Bounds firstB = GetWorldBounds(first);
        float currentFrontMaxZ = firstB.max.z;

        for (int i = 1; i < segments.Count; i++)
        {
            Transform seg = segments[i];
            if (seg == null) continue;

            Bounds b = GetWorldBounds(seg);
            float pivotToMin = seg.position.z - b.min.z;

            Vector3 p = seg.position;
            // Bu segmentin minZ'sini bir �ncekinin maxZ'sine yap��t�r
            p.z = currentFrontMaxZ + pivotToMin;
            seg.position = p;

            // Yeni front max g�ncelle
            Bounds newB = GetWorldBounds(seg);
            currentFrontMaxZ = newB.max.z;
        }
    }

    private float FindFrontMostMaxZ()
    {
        float maxZ = float.NegativeInfinity;
        for (int i = 0; i < segments.Count; i++)
        {
            if (segments[i] == null) continue;
            Bounds b = GetWorldBounds(segments[i]);
            if (b.max.z > maxZ) maxZ = b.max.z;
        }
        return maxZ;
    }

    private Bounds GetWorldBounds(Transform root)
    {
        // Root alt�ndaki T�M rendererlardan birle�ik bounds ��kar�r (as�l fix burada)
        Renderer[] rs = root.GetComponentsInChildren<Renderer>();
        if (rs == null || rs.Length == 0)
        {
            // Renderer yoksa fallback: k���k bir bounds
            return new Bounds(root.position, Vector3.one);
        }

        Bounds b = rs[0].bounds;
        for (int i = 1; i < rs.Length; i++)
            b.Encapsulate(rs[i].bounds);

        return b;
    }
}

using UnityEngine;

/// <summary>
/// Tüm combat parametrelerinin tek yeri.
