using TMPro;
using UnityEngine;

public class SwipeDebugHUD : MonoBehaviour
{
    [Header("References")]
    [SerializeField] private SwipeInput swipe;
    [SerializeField] private SwipeInterpreter interpreter;
    [SerializeField] private TMP_Text text;

    private void Reset()
    {
        if (swipe == null)
            swipe = GetComponent<SwipeInput>();

        if (interpreter == null)
            interpreter = GetComponent<SwipeInterpreter>();
    }

    private void Awake()
    {
        if (swipe == null)
            swipe = GetComponent<SwipeInput>();

        if (interpreter == null)
            interpreter = GetComponent<SwipeInterpreter>();
    }

    private void Update()
    {
        if (text == null)
            return;

        string swipePart = "Swipe: missing";
        if (swipe != null)
        {
            swipePart =
                $"IsDown: {swipe.IsDown}\n" +
                $"DeltaPx: {swipe.DeltaPx}\n" +
                $"DeltaNorm: {swipe.DeltaNormalized}";
        }

        string interpreterPart = "Interpreter: missing";
        if (interpreter != null)
        {
            interpreterPart =
                $"CurrentDir: {interpreter.CurrentDirection}\n" +
                $"LastCommitted: {interpreter.LastCommittedDirection}\n" +
                $"AccumPx: {interpreter.AccumulatedDeltaPx}\n" +
                $"CommittedThisPress: {interpreter.HasCommittedThisPress}";
        }

        text.text = swipePart + "\n\n" + interpreterPart;
    }
}

using System;
using UnityEngine;

public class SwipeInput : MonoBehaviour
{
    [Header("Tuning")]
    [Tooltip("Deadzone in pixels. Smaller = more sensitive.")]
    [SerializeField] private float deadzonePx = 10f;

    [Tooltip("Max delta magnitude in pixels for normalization clamp.")]
    [SerializeField] private float maxDeltaPx = 300f;

    [Tooltip("If true, swipe is measured relative to initial press position (absolute). If false, per-frame delta.")]
    [SerializeField] private bool useAbsoluteFromStart = false;

    [Header("Read-only (Debug)")]
    [SerializeField] private bool isDown;
    [SerializeField] private Vector2 startPos;
    [SerializeField] private Vector2 currentPos;
    [SerializeField] private Vector2 deltaPx;
    [SerializeField] private Vector2 deltaNormalized;

    public bool IsDown => isDown;
    public Vector2 FingerPosition => currentPos;

    public Vector2 DeltaPx => deltaPx;
    public Vector2 RawDeltaPx { get; private set; }  // Deadzone olmadan, hit-test icin

    public Vector2 DeltaNormalized => deltaNormalized;

    // Events
    public event Action OnPress;
    public event Action OnRelease;

    private int activeFingerId = -1;
    private Vector2 lastPos;

private void Update()
    {
        if (Input.touchCount > 0)
            HandleTouch();
        else
            HandleMouse();

        if (isDown)
        {
            Vector2 rawDelta = currentPos - lastPos;
            RawDeltaPx = rawDelta;  // Deadzone yok

            if (useAbsoluteFromStart)
                deltaPx = currentPos - startPos;
            else
                deltaPx = rawDelta;

            if (deltaPx.magnitude < deadzonePx)
                deltaPx = Vector2.zero;

            float mag = Mathf.Min(deltaPx.magnitude, maxDeltaPx);
            deltaNormalized = (mag <= 0.001f) ? Vector2.zero : (deltaPx.normalized * (mag / maxDeltaPx));
        }
        else
        {
            deltaPx = Vector2.zero;
            deltaNormalized = Vector2.zero;
            RawDeltaPx = Vector2.zero;
        }

        lastPos = currentPos;
    }

    private void HandleMouse()
    {
        if (Input.GetMouseButtonDown(0))
        {
            isDown = true;
            activeFingerId = -1;

            startPos = Input.mousePosition;
            currentPos = startPos;
            lastPos = startPos;

            OnPress?.Invoke();
        }

        if (isDown && Input.GetMouseButton(0))
        {
            currentPos = Input.mousePosition;
        }

        if (isDown && Input.GetMouseButtonUp(0))
        {
            isDown = false;
            activeFingerId = -1;

            OnRelease?.Invoke();
        }
    }

    private void HandleTouch()
    {
        // If we don't have an active finger, grab the first Began
        if (activeFingerId == -1)
        {
            for (int i = 0; i < Input.touchCount; i++)
            {
                Touch t = Input.GetTouch(i);
                if (t.phase == TouchPhase.Began)
                {
                    activeFingerId = t.fingerId;
                    isDown = true;

                    startPos = t.position;
                    currentPos = startPos;
                    lastPos = startPos;

                    OnPress?.Invoke();
                    break;
                }
            }
        }

        // Track active finger
        if (activeFingerId != -1)
        {
            bool found = false;

            for (int i = 0; i < Input.touchCount; i++)
            {
                Touch t = Input.GetTouch(i);
                if (t.fingerId != activeFingerId) continue;

                found = true;

                if (t.phase == TouchPhase.Moved || t.phase == TouchPhase.Stationary)
                {
                    currentPos = t.position;
                }
                else if (t.phase == TouchPhase.Ended || t.phase == TouchPhase.Canceled)
                {
                    isDown = false;
                    activeFingerId = -1;

                    OnRelease?.Invoke();
                }

                break;
            }

            // Safety: if active finger disappeared
            if (!found)
            {
                isDown = false;
                activeFingerId = -1;
                OnRelease?.Invoke();
            }
        }
    }
}

using UnityEngine;

public enum SwipeDirection
{
    None = 0,
    Left = 1,
    Right = 2,
    Up = 3,
    Down = 4
}

/// <summary>
/// Interprets SwipeInput into cardinal directions and supports multi-commit chains
/// within a single press.
///
/// Core behavior:
/// - While the finger/mouse is held, we accumulate a SEGMENT delta.
/// - When that segment clearly resolves into a direction and passes commitDistancePx,
///   we commit one chain step.
/// - After commit, the segment resets so the next turn can be read as a new step.
/// - Releasing the finger resets the whole chain state for this input layer.
///
/// This fits zig-zag weakpoint paths better than whole-press accumulation.
/// </summary>
public class SwipeInterpreter : MonoBehaviour
{
    [Header("References")]
    [SerializeField] private SwipeInput swipe;
    [SerializeField] private MonoBehaviour combatReceiver;

    [Header("Direction Commit Tuning")]
    [Tooltip("Segment distance required before a direction is committed.")]
    [SerializeField] private float commitDistancePx = 70f;

    [Tooltip("How much stronger the dominant axis should be. 1.0 = no bias, 1.2 = 20% stronger.")]
    [SerializeField] private float dominantAxisBias = 1.15f;

    [Tooltip("If false, diagonal/ambiguous swipes are ignored until direction becomes clear enough.")]
    [SerializeField] private bool allowDominantAxisFallback = true;

    [Tooltip("Prevents same-direction spam within the same press. Recommended true for chain combat.")]
    [SerializeField] private bool blockSameDirectionRepeatInSamePress = true;

    [Header("Read-only (Debug)")]
    [SerializeField] private bool wasDownLastFrame;
    [SerializeField] private bool hasCommittedThisPress;
    [SerializeField] private Vector2 accumulatedDeltaPx;
    [SerializeField] private SwipeDirection currentDirection = SwipeDirection.None;
    [SerializeField] private SwipeDirection lastCommittedDirection = SwipeDirection.None;
    [SerializeField] private int committedCountThisPress;

    public bool HasCommittedThisPress => hasCommittedThisPress;
    public Vector2 AccumulatedDeltaPx => accumulatedDeltaPx;
    public SwipeDirection CurrentDirection => currentDirection;
    public SwipeDirection LastCommittedDirection => lastCommittedDirection;
    public int CommittedCountThisPress => committedCountThisPress;

    private void Reset()
    {
        swipe = GetComponent<SwipeInput>();
    }

    private void Awake()
    {
        if (swipe == null)
            swipe = GetComponent<SwipeInput>();
    }

    private void Update()
    {
        if (swipe == null)
            return;

        bool isDown = swipe.IsDown;

        if (isDown && !wasDownLastFrame)
            BeginPress();

        if (isDown)
            UpdateHeldPress();

        if (!isDown && wasDownLastFrame)
            EndPress();

        wasDownLastFrame = isDown;
    }

    private void BeginPress()
    {
        hasCommittedThisPress = false;
        committedCountThisPress = 0;
        accumulatedDeltaPx = Vector2.zero;
        currentDirection = SwipeDirection.None;
        lastCommittedDirection = SwipeDirection.None;
    }

    private void EndPress()
    {
        hasCommittedThisPress = false;
        committedCountThisPress = 0;
        accumulatedDeltaPx = Vector2.zero;
        currentDirection = SwipeDirection.None;
        lastCommittedDirection = SwipeDirection.None;
    }

    private void UpdateHeldPress()
    {
        accumulatedDeltaPx += swipe.DeltaPx;

        SwipeDirection preview = EvaluateDirection(accumulatedDeltaPx);
        currentDirection = preview;

        if (preview == SwipeDirection.None)
            return;

        if (accumulatedDeltaPx.magnitude < commitDistancePx)
            return;

        if (blockSameDirectionRepeatInSamePress && committedCountThisPress > 0 && preview == lastCommittedDirection)
        {
            // Prevent repeated firing from a long drag in the same direction.
            // Reset the current segment and wait for a meaningful turn.
            accumulatedDeltaPx = Vector2.zero;
            currentDirection = SwipeDirection.None;
            return;
        }

        CommitDirection(preview);
    }

    private void CommitDirection(SwipeDirection direction)
    {
        hasCommittedThisPress = true;
        committedCountThisPress++;
        currentDirection = direction;
        lastCommittedDirection = direction;

        if (combatReceiver != null)
        {
            combatReceiver.SendMessage("OnSwipeDirection", direction, SendMessageOptions.DontRequireReceiver);
            combatReceiver.SendMessage("OnSwipeDirectionCommitted", direction, SendMessageOptions.DontRequireReceiver);
        }

        // Start a fresh segment immediately so the same press can continue chaining.
        accumulatedDeltaPx = Vector2.zero;
        currentDirection = SwipeDirection.None;
    }

    private SwipeDirection EvaluateDirection(Vector2 delta)
    {
        if (delta.magnitude < commitDistancePx)
            return SwipeDirection.None;

        float absX = Mathf.Abs(delta.x);
        float absY = Mathf.Abs(delta.y);

        bool xDominant = absX >= absY * dominantAxisBias;
        bool yDominant = absY >= absX * dominantAxisBias;

        if (xDominant)
            return delta.x >= 0f ? SwipeDirection.Right : SwipeDirection.Left;

        if (yDominant)
            return delta.y >= 0f ? SwipeDirection.Up : SwipeDirection.Down;

        if (!allowDominantAxisFallback)
            return SwipeDirection.None;

        return absX >= absY
            ? (delta.x >= 0f ? SwipeDirection.Right : SwipeDirection.Left)
            : (delta.y >= 0f ? SwipeDirection.Up : SwipeDirection.Down);
    }
}

using UnityEngine;

public class BillboardFacing : MonoBehaviour
{
    private Camera cam;

    void Start()
    {
        cam = Camera.main;
    }

    void LateUpdate()
    {
        if (cam == null)
        {
            cam = Camera.main;
            if (cam == null) return;
        }

        // Make the object face the camera
        Vector3 dir = transform.position - cam.transform.position;
        dir.y = 0f; // keep upright so it doesn't tilt

        if (dir.sqrMagnitude > 0.001f)
        {
            transform.rotation = Quaternion.LookRotation(-dir);
        }
    }
}

using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using System.Text;
using Newtonsoft.Json;
using UnityEngine;

#if UNITY_EDITOR
using UnityEditor;
using UnityEditor.SceneManagement;

public class ClaudeSnapshotTool : EditorWindow
{
    private string extractCommand = "";
    private string statusMessage = "";
    private bool snapshotReady = false;

    // Sabit yollar — her seferinde üzerine yazılır
    private static readonly string ToolFolder = "Assets/_Project/DevTool/ClaudeSnapshot";
    private static readonly string SnapshotPath = "Assets/_Project/DevTool/ClaudeSnapshot/claude_snapshot.json";
    private static readonly string ExtractPath = "Assets/_Project/DevTool/ClaudeSnapshot/claude_extract.md";
    private static readonly string IndexPath = "Assets/_Project/DevTool/ClaudeSnapshot/claude_index.md";

    // ─────────────────────────────────────
    // MENU
    // ─────────────────────────────────────

    [MenuItem("Tools/BladeRift/Project State/Claude Snapshot")]
    public static void OpenTool()
    {
        // 1) Snapshot al
        TakeSnapshot();

        // 2) Pencereyi aç
        var window = GetWindow<ClaudeSnapshotTool>("Claude Extract");
        window.minSize = new Vector2(420, 200);
        window.snapshotReady = true;
        window.statusMessage = "Snapshot alındı. Extract komutunu yapıştır.";
        window.Show();
    }

    // ─────────────────────────────────────
    // GUI
    // ─────────────────────────────────────

    private void OnGUI()
    {
        GUILayout.Label("Claude Snapshot Tool", EditorStyles.boldLabel);
        GUILayout.Space(5);

        if (!snapshotReady)
        {
            EditorGUILayout.HelpBox("Önce menüden Claude Snapshot çalıştır.", MessageType.Info);
            return;
        }

        GUILayout.Label("Extract komutu:");
        GUILayout.Label("Örnek: CombatDirector, RageManager --scene --logs", EditorStyles.miniLabel);
        extractCommand = EditorGUILayout.TextField(extractCommand);

        GUILayout.Space(10);

        if (GUILayout.Button("Extract", GUILayout.Height(30)))
        {
            RunExtract();
        }

        GUILayout.Space(10);

        if (!string.IsNullOrEmpty(statusMessage))
        {
            EditorGUILayout.HelpBox(statusMessage, MessageType.Info);
        }
    }

    // ─────────────────────────────────────
    // SNAPSHOT
    // ─────────────────────────────────────

    private static void TakeSnapshot()
    {
        Directory.CreateDirectory(ToolFolder);

        var scene = EditorSceneManager.GetActiveScene();
        if (!scene.IsValid())
        {
            Debug.LogError("[ClaudeSnapshot] Active scene is not valid.");
            return;
        }

        FullSnapshot full = new FullSnapshot();
        full.meta.snapshotKind = "CLAUDE";
        full.meta.exportedAtLocalTime = DateTime.Now.ToString("yyyy-MM-dd HH:mm:ss");
        full.meta.unityVersion = Application.unityVersion;
        full.meta.platform = Application.platform.ToString();
        full.meta.activeSceneName = scene.name;
        full.meta.note = "Claude AI snapshot.";
        full.scene.sceneName = scene.name;
        full.scene.scenePath = scene.path;

        var roots = scene.GetRootGameObjects();
        full.meta.rootObjectCount = roots.Length;
        full.meta.totalGameObjectCount = ProjectStateSerializer.CountAllSceneObjects(scene);
        full.meta.headCommitShort = ProjectStateGit.SafeGit("rev-parse --short HEAD");
        full.meta.headCommitFull = ProjectStateGit.SafeGit("rev-parse HEAD");
        full.meta.headCommitMessage = ProjectStateGit.SafeGit("log -1 --pretty=%s");

        foreach (var root in roots)
            full.scene.roots.Add(ProjectStateSerializer.SerializeGameObjectRecursive(root, root.name));

        ProjectStateSerializer.FillProjectSnapshot(full.project);
        ProjectStateSerializer.FillCodeSnapshot(full.code);
        ProjectStateSerializer.FillDocsSnapshot(full.docs);

        // Konsol loglarını da yakala
        // (MiniSnapshot'taki gibi ama FullSnapshot'a ek alan olarak değil, ayrıca saklayacağız)

        var settings = new JsonSerializerSettings
        {
            Formatting = Formatting.Indented,
            ReferenceLoopHandling = ReferenceLoopHandling.Ignore
        };
        File.WriteAllText(SnapshotPath, JsonConvert.SerializeObject(full, settings), Encoding.UTF8);

        // INDEX her snapshot'ta otomatik üretilir
        GenerateIndex(full);

        AssetDatabase.Refresh();
        Debug.Log($"[ClaudeSnapshot] Snapshot alındı: {SnapshotPath}");
    }

    // ─────────────────────────────────────
    // INDEX — her zaman otomatik üretilir
    // ─────────────────────────────────────

    private static void GenerateIndex(FullSnapshot full)
    {
        var sb = new StringBuilder();
        sb.AppendLine("# CLAUDE INDEX");
        sb.AppendLine($"commit: {full.meta.headCommitShort} | message: {full.meta.headCommitMessage}");
        sb.AppendLine($"scene: {full.meta.activeSceneName} | roots: {full.meta.rootObjectCount} | objects: {full.meta.totalGameObjectCount}");
        sb.AppendLine($"unity: {full.meta.unityVersion} | export: {full.meta.exportedAtLocalTime}");
        sb.AppendLine();

        // Compile check
        bool hasCompileErrors = false;
#if UNITY_EDITOR
        // Basit kontrol — compile error varsa Unity zaten loglar
        hasCompileErrors = EditorUtility.scriptCompilationFailed;
#endif
        sb.AppendLine($"compile: {(hasCompileErrors ? "ERRORS" : "clean")}");
        sb.AppendLine();

        // CS dosya listesi (sadece game code, DevTool/TutorialInfo hariç)
        sb.AppendLine("## Files");
        foreach (var f in full.code.csFiles)
        {
            string rp = f.relativePath.Replace("\\", "/");
            if (rp.Contains("ProjectState") || rp.Contains("TutorialInfo") || rp.Contains("DevTool"))
                continue;

            string name = Path.GetFileNameWithoutExtension(rp);
            string size = f.sizeBytes < 1024 ? $"{f.sizeBytes}B" : $"{f.sizeBytes / 1024}K";
            sb.AppendLine($"  {name} ({size}) — {rp}");
        }
        sb.AppendLine();

        // Component map (kısa — her root altında ne var)
        sb.AppendLine("## Components");
        foreach (var root in full.scene.roots)
        {
            WriteComponentMapCompact(sb, root, 0);
        }
        sb.AppendLine();

        File.WriteAllText(IndexPath, sb.ToString(), Encoding.UTF8);
    }

    private static void WriteComponentMapCompact(StringBuilder sb, GameObjectData obj, int depth)
    {
        string indent = new string(' ', depth * 2);
        var customComps = obj.components
            .Where(c => !c.type.StartsWith("UnityEngine.") && !c.type.StartsWith("TMPro."))
            .Select(c => c.type)
            .ToList();

        bool hasChildren = obj.children != null && obj.children.Count > 0;

        if (customComps.Count > 0)
        {
            sb.AppendLine($"{indent}{obj.name} [{string.Join(" | ", customComps)}]");
        }
        else if (depth == 0 || hasChildren)
        {
            // Root her zaman göster + child'ı olan ara node'ları da göster
            sb.AppendLine($"{indent}{obj.name}");
        }

        if (obj.children != null)
        {
            foreach (var child in obj.children)
                WriteComponentMapCompact(sb, child, depth + 1);
        }
    }

    // ─────────────────────────────────────
    // EXTRACT
    // ─────────────────────────────────────

    private void RunExtract()
    {
        if (!File.Exists(SnapshotPath))
        {
            statusMessage = "Snapshot bulunamadı. Önce Claude Snapshot al.";
            return;
        }

        // Snapshot'ı oku
        FullSnapshot full;
        try
        {
            string json = File.ReadAllText(SnapshotPath, Encoding.UTF8);
            // BOM varsa temizle
            if (json.Length > 0 && json[0] == '\uFEFF')
                json = json.Substring(1);
            full = JsonConvert.DeserializeObject<FullSnapshot>(json);
        }
        catch (Exception ex)
        {
            statusMessage = $"Snapshot okunamadı: {ex.Message}";
            return;
        }

        // Komutu parse et
        ParseResult parsed = ParseCommand(extractCommand);

        var sb = new StringBuilder();
        sb.AppendLine("# CLAUDE EXTRACT");
        sb.AppendLine($"snapshot: {full.meta.headCommitShort} | {full.meta.exportedAtLocalTime}");
        sb.AppendLine($"compile: {(EditorUtility.scriptCompilationFailed ? "ERRORS" : "clean")}");
        sb.AppendLine($"command: {extractCommand}");
        sb.AppendLine();

        int fileCount = 0;

        // İstenen CS dosyalarını çıkar
        if (parsed.fileNames.Count > 0)
        {
            foreach (string requested in parsed.fileNames)
            {
                var match = full.code.csFiles.FirstOrDefault(f =>
                {
                    string name = Path.GetFileNameWithoutExtension(f.relativePath.Replace("\\", "/"));
                    return string.Equals(name, requested, StringComparison.OrdinalIgnoreCase);
                });

                if (match != null)
                {
                    sb.AppendLine($"## {Path.GetFileName(match.relativePath)}");
                    sb.AppendLine($"path: {match.relativePath}");
                    sb.AppendLine("```csharp");
                    sb.AppendLine(match.text);
                    sb.AppendLine("```");
                    sb.AppendLine();
                    fileCount++;
                }
                else
                {
                    sb.AppendLine($"## {requested}.cs — BULUNAMADI");
                    sb.AppendLine();
                }
            }
        }

        // Scene
        if (parsed.includeScene)
        {
            sb.AppendLine("## Scene Hierarchy");
            foreach (var root in full.scene.roots)
            {
                WriteSceneTree(sb, root, 0);
            }
            sb.AppendLine();
        }

        // Console logs
        if (parsed.includeLogs)
        {
            sb.AppendLine("## Console Logs (son 20)");
            // FullSnapshot'ta consoleLogs yok, MiniSnapshot'ta var
            // Burada Unity console'dan direkt okuyalım
            sb.AppendLine("(Console log yakalama için MINI snapshot kullanılabilir)");
            sb.AppendLine();
        }

        // Compile errors
        if (EditorUtility.scriptCompilationFailed)
        {
            sb.AppendLine("## Compile Errors");
            sb.AppendLine("UYARI: Compile hatası mevcut. Detay için Unity Console'a bak.");
            sb.AppendLine();
        }

        File.WriteAllText(ExtractPath, sb.ToString(), Encoding.UTF8);
        AssetDatabase.Refresh();

        statusMessage = $"Extract tamamlandı. {fileCount} dosya çıkarıldı.\n{ExtractPath}";
        EditorUtility.RevealInFinder(ExtractPath);
    }

    private static void WriteSceneTree(StringBuilder sb, GameObjectData obj, int depth)
    {
        string indent = new string(' ', depth * 2);
        var comps = obj.components
            .Select(c => c.type.Replace("UnityEngine.", "").Replace("UnityEngine.Rendering.Universal.", ""))
            .Where(c => c != "Transform" && c != "RectTransform")
            .ToList();

        string compStr = comps.Count > 0 ? $" [{string.Join(" | ", comps)}]" : "";
        sb.AppendLine($"{indent}{obj.name}{compStr}");

        foreach (var child in obj.children)
            WriteSceneTree(sb, child, depth + 1);
    }

    // ─────────────────────────────────────
    // PARSE
    // ─────────────────────────────────────

    private struct ParseResult
    {
        public List<string> fileNames;
        public bool includeScene;
        public bool includeLogs;
    }

    private static ParseResult ParseCommand(string cmd)
    {
        var result = new ParseResult
        {
            fileNames = new List<string>(),
            includeScene = false,
            includeLogs = false
        };

        if (string.IsNullOrWhiteSpace(cmd))
            return result;

        // Flags
        string remaining = cmd;

        if (remaining.Contains("--scene"))
        {
            result.includeScene = true;
            remaining = remaining.Replace("--scene", "").Trim();
        }

        if (remaining.Contains("--logs"))
        {
            result.includeLogs = true;
            remaining = remaining.Replace("--logs", "").Trim();
        }

        // Kalan kısım virgülle ayrılmış dosya isimleri
        if (!string.IsNullOrWhiteSpace(remaining))
        {
            var names = remaining.Split(new[] { ',', ' ' }, StringSplitOptions.RemoveEmptyEntries);
            foreach (var n in names)
            {
                string clean = n.Trim().Replace(".cs", "");
                if (!string.IsNullOrEmpty(clean))
                    result.fileNames.Add(clean);
            }
        }

        return result;
    }
}

